{
    "preset": "laravel"
}

@import 'tailwindcss';

@import 'tw-animate-css';

@source '../views';
@source '../../vendor/laravel/framework/src/Illuminate/Pagination/resources/views/*.blade.php';

@custom-variant dark (&:is(.dark *));

@theme {
    --font-sans:
        'Red Hat Display', ui-sans-serif, system-ui, sans-serif,
        'Apple Color Emoji', 'Segoe UI Emoji', 'Segoe UI Symbol',
        'Noto Color Emoji';

    --font-mono:
        'JetBrains Mono', ui-monospace, monospace;

    --radius-lg: var(--radius);
    --radius-md: calc(var(--radius) - 2px);
    --radius-sm: calc(var(--radius) - 4px);

    --color-background: var(--background);
    --color-foreground: var(--foreground);

    --color-card: var(--card);
    --color-card-foreground: var(--card-foreground);

    --color-popover: var(--popover);
    --color-popover-foreground: var(--popover-foreground);

    --color-primary: var(--primary);
    --color-primary-foreground: var(--primary-foreground);

    --color-secondary: var(--secondary);
    --color-secondary-foreground: var(--secondary-foreground);

    --color-muted: var(--muted);
    --color-muted-foreground: var(--muted-foreground);

    --color-accent: var(--accent);
    --color-accent-foreground: var(--accent-foreground);

    --color-destructive: var(--destructive);
    --color-destructive-foreground: var(--destructive-foreground);

    --color-success: var(--success);
    --color-success-foreground: var(--success-foreground);

    --color-border: var(--border);
    --color-input: var(--input);
    --color-ring: var(--ring);

    --color-chart-1: var(--chart-1);
    --color-chart-2: var(--chart-2);
    --color-chart-3: var(--chart-3);
    --color-chart-4: var(--chart-4);
    --color-chart-5: var(--chart-5);

    --color-sidebar: var(--sidebar);
    --color-sidebar-foreground: var(--sidebar-foreground);
    --color-sidebar-primary: var(--sidebar-primary);
    --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);

    --color-sidebar-accent: var(--sidebar-accent);
    --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
    --color-sidebar-border: var(--sidebar-border);
    --color-sidebar-ring: var(--sidebar-ring);
}

/* Light mode (default - but we'll force dark for CTF) */
:root {
    --background: oklch(0.98 0 0);
    --foreground: oklch(0.145 0 0);
    --card: oklch(1 0 0);
    --card-foreground: oklch(0.145 0 0);
    --popover: oklch(1 0 0);
    --popover-foreground: oklch(0.145 0 0);
    --primary: oklch(0.55 0.22 25); /* Red */
    --primary-foreground: oklch(0.98 0 0);
    --secondary: oklch(0.97 0 0);
    --secondary-foreground: oklch(0.205 0 0);
    --muted: oklch(0.97 0 0);
    --muted-foreground: oklch(0.556 0 0);
    --accent: oklch(0.97 0 0);
    --accent-foreground: oklch(0.205 0 0);
    --destructive: oklch(0.577 0.245 27.325);
    --destructive-foreground: oklch(0.98 0 0);
    --success: oklch(0.6 0.2 145);
    --success-foreground: oklch(0.98 0 0);
    --border: oklch(0.922 0 0);
    --input: oklch(0.922 0 0);
    --ring: oklch(0.55 0.22 25);
    --chart-1: oklch(0.55 0.22 25);
    --chart-2: oklch(0.6 0.118 184.704);
    --chart-3: oklch(0.398 0.07 227.392);
    --chart-4: oklch(0.828 0.189 84.429);
    --chart-5: oklch(0.769 0.188 70.08);
    --radius: 0.5rem;
    --sidebar: oklch(0.985 0 0);
    --sidebar-foreground: oklch(0.145 0 0);
    --sidebar-primary: oklch(0.55 0.22 25);
    --sidebar-primary-foreground: oklch(0.985 0 0);
    --sidebar-accent: oklch(0.97 0 0);
    --sidebar-accent-foreground: oklch(0.205 0 0);
    --sidebar-border: oklch(0.922 0 0);
    --sidebar-ring: oklch(0.55 0.22 25);
}

/* HTB-inspired Red Dark Theme - Softer, less contrast */
.dark {
    --background: oklch(0.13 0.005 250); /* Dark blue-gray like HTB */
    --foreground: oklch(0.88 0 0); /* Softer white */
    --card: oklch(0.16 0.005 250); /* Slightly lighter card */
    --card-foreground: oklch(0.88 0 0);
    --popover: oklch(0.16 0.005 250);

    --popover-foreground: oklch(0.88 0 0);
    --primary: oklch(0.6 0.2 25); /* Muted Red accent */
    --primary-foreground: oklch(0.98 0 0);
    --secondary: oklch(0.2 0.005 250); /* Dark blue-gray */
    --secondary-foreground: oklch(0.85 0 0);
    --muted: oklch(0.22 0.005 250);
    --muted-foreground: oklch(0.55 0 0); /* Softer gray text */
    --accent: oklch(0.25 0.01 250); /* Subtle accent */
    --accent-foreground: oklch(0.88 0 0);
    --destructive: oklch(0.55 0.18 25);
    --destructive-foreground: oklch(0.98 0 0);
    --success: oklch(0.55 0.15 145);
    --success-foreground: oklch(0.98 0 0);
    --border: oklch(0.25 0.005 250); /* Subtle border */
    --input: oklch(0.2 0.005 250);
    --ring: oklch(0.6 0.2 25);
    --chart-1: oklch(0.6 0.2 25);
    --chart-2: oklch(0.6 0.15 162);
    --chart-3: oklch(0.65 0.15 70);
    --chart-4: oklch(0.55 0.2 303);
    --chart-5: oklch(0.6 0.2 16);
    --sidebar: oklch(0.11 0.005 250);
    --sidebar-foreground: oklch(0.85 0 0);
    --sidebar-primary: oklch(0.6 0.2 25);
    --sidebar-primary-foreground: oklch(0.98 0 0);
    --sidebar-accent: oklch(0.2 0.01 250);
    --sidebar-accent-foreground: oklch(0.85 0 0);
    --sidebar-border: oklch(0.25 0.005 250);
    --sidebar-ring: oklch(0.6 0.2 25);
}

@layer base {
    * {
        @apply border-border;
    }

    body {
        @apply bg-background text-foreground;
    }

    /* Custom scrollbar for CTF theme */
    ::-webkit-scrollbar {
        width: 8px;
        height: 8px;
    }

    ::-webkit-scrollbar-track {
        background: oklch(0.15 0.005 250);
    }

    ::-webkit-scrollbar-thumb {
        background: oklch(0.28 0.005 250);
        border-radius: 4px;
    }

    ::-webkit-scrollbar-thumb:hover {
        background: oklch(0.6 0.2 25);
    }
}

/* CTF specific utilities */
@layer utilities {
    .ctf-glow {
        box-shadow: 0 0 20px oklch(0.6 0.2 25 / 0.25);
    }

    .ctf-glow-sm {
        box-shadow: 0 0 10px oklch(0.6 0.2 25 / 0.15);
    }

    .ctf-border-glow {
        border-color: oklch(0.6 0.2 25 / 0.4);
        box-shadow: 0 0 10px oklch(0.6 0.2 25 / 0.15);
    }

    .text-gradient-red {
        background: linear-gradient(135deg, oklch(0.65 0.2 25), oklch(0.5 0.18 30));
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
    }

    .bg-gradient-dark {
        background: linear-gradient(180deg, oklch(0.13 0.005 250) 0%, oklch(0.16 0.005 250) 100%);
    }

    .bg-pattern-grid {
        background-image: 
            linear-gradient(oklch(0.25 0.005 250 / 0.3) 1px, transparent 1px),
            linear-gradient(90deg, oklch(0.25 0.005 250 / 0.3) 1px, transparent 1px);
        background-size: 40px 40px;
    }
}

